/**
	 * Add Headers
	 *
	 * @since 5.4.0
	 * @access public
	 */
function add_headers() {
		// Check if tags mode is enabled - per-request check to allow dynamic toggling.
		if ( ! get_site_option( 'vhp_varnish_use_tags' ) ) {
			return;
		}

		if ( headers_sent() ) {
			return;
		}

		$tags = $this->get_tags();

		if ( empty( $tags ) ) {
			return;
		}

		// Allow filtering of the header name.
		$header_name = apply_filters( 'vhp_cache_tags_header', 'X-Cache-Tags' );

		// Allow filtering of the tags.
		$tags = apply_filters( 'vhp_cache_tags', $tags );

		// Output the header.
		header( sprintf( '%s: %s', $header_name, implode( ',', $tags ) ) );
	}

