/**
		 * Checks if template with given id exists
		 *
		 * @since 1.0.0
		 */
function is_template($template_id) {

			$template = get_post($template_id);

			if($template) {
				if($template->post_type != 'template' || $template->post_status != 'publish') return false;
			} else {
				return false;
			}

			return true;

		}

